    /** Basic chat completion via the Anthropic provider (claude-3-5-sonnet-20241022) with system and user messages */
    public function test_anthropic_chat(): void
    {
        $client = \Liter\Llm\LiterLlm::createClient('test-key', getenv('MOCK_SERVER_URL') . '/fixtures/anthropic_chat');
        $request = \Liter\Llm\ChatCompletionRequest::from_json(json_encode(["maxTokens" => 16, "messages" => [["content" => "You are a helpful assistant.", "role" => "system"], ["content" => "Say hello in one word.", "role" => "user"]], "model" => "anthropic/claude-3-5-sonnet-20241022", "temperature" => 0]));
        $result = $client->chat($request);

            $this->assertCount(1, $result->getChoices());
            $this->assertEquals("Hello!", trim(($result->getChoices()[0]->getMessage()->content ?? null)));
            $this->assertEquals("stop", trim(($result->getChoices()[0]->finishReason ?? null)));
            $this->assertEquals("claude-3-5-sonnet-20241022", trim($result->model));
            $this->assertEquals(23, $result->getUsage()->totalTokens);


    }


